from typing import Optional

class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

class Solution:
    def isPalindrome(self, head: Optional[ListNode]) -> bool:
        if not head or not head.next:
            return True

        slow = head
        fast = head
        while fast and fast.next:
            slow = slow.next
            fast = fast.next.next

        second_half_head = self._reverseList(slow)

        first_half_current = head
        second_half_current = second_half_head

        while second_half_current:
            if first_half_current.val != second_half_current.val:
                return False
            first_half_current = first_half_current.next
            second_half_current = second_half_current.next

        return True

    def _reverseList(self, head: Optional[ListNode]) -> Optional[ListNode]:
        prev = None
        current = head
        while current:
            next_node = current.next
            current.next = prev
            prev = current
            current = next_node
        return prev
